const MOBILEPAY_NUMBER = '+45 55 26 57 35';
const REVOLUT_LINK = 'https://revolut.me/rohhowe';
const REVOLUT_HANDLE = '@rohhowe';

const CLASS_DATES = ['Lunes 4', 'Lunes 18', 'Lunes 25', 'Lunes 1'];
const CLASS_TIMES = { 'Lunes 4': '18:30', 'Lunes 18': '18:30', 'Lunes 25': '18:30', 'Lunes 1': '18:30' };

const DANCER_IMG = "data:image/png;base64,";

function PoleIllustration() {
  return (
    <img
      src={DANCER_IMG}
      alt=""
      aria-hidden="true"
      style={{ width: 90, height: 'auto', flexShrink: 0, display: 'block' }}
    />
  );
}

export default function PoleBooking() {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [adminMode, setAdminMode] = useState(false);
  const [showPasswordPrompt, setShowPasswordPrompt] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [saving, setSaving] = useState(false);
  const [step, setStep] = useState('form'); // form -> payment -> done
  const [pendingId, setPendingId] = useState(null);

  const loadStudents = useCallback(async () => {
    try {
      const data = await fetchReservas();
      setStudents(data);
    } catch (e) {
      setStudents([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadStudents();
  }, [loadStudents]);

  const handleAdd = async () => {
    const trimmed = name.trim();
    if (!trimmed) { setError('Escribí tu nombre.'); return; }
    setError('');
    setSaving(true);
    try {
      const latest = await fetchReservas();
      setStudents(latest);
      if (latest.some(s => s.name.toLowerCase() === trimmed.toLowerCase())) { setError('Ese nombre ya está anotado.'); return; }
      await insertReserva(trimmed);
      const newStudent = { id: Date.now(), name: trimmed, paid: false };
      setStudents(prev => [...prev, newStudent]);
      setPendingId(newStudent.id);
      setStep('payment');
    } catch (e) {
      setError('No se pudo guardar. Revisá tu conexión e intentá de nuevo.');
    } finally {
      setSaving(false);
    }
  };

  const confirmPaid = async () => {
    setStudents(prev => prev.map(s => s.id === pendingId ? { ...s, paid: true } : s));
    setStep('done');
  };

  const togglePaid = async (id) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, paid: !s.paid } : s));
  };

  const removeStudent = async (id) => {
    setStudents(prev => prev.filter(s => s.id !== id));
  };

  const resetForm = () => {
    setName('');
    setStep('form');
    setPendingId(null);
  };

  const handleAdminClick = () => {
    if (adminMode) {
      setAdminMode(false);
      return;
    }
    setShowPasswordPrompt(true);
    setPasswordInput('');
    setPasswordError('');
  };

  const checkPassword = () => {
    if (passwordInput === ADMIN_PASSWORD) {
      setAdminMode(true);
      setShowPasswordPrompt(false);
      setPasswordInput('');
      setPasswordError('');
    } else {
      setPasswordError('Contraseña incorrecta.');
    }
  };

  if (loading) {
    return (
      <div style={{ padding: '3rem 1rem', textAlign: 'center', color: '#A87C8C' }}>
        Cargando reservas...
      </div>
    );
  }

  const count = students.length;
  const pct = Math.min(100, Math.round((count / MAX_CUPOS) * 100));
  const full = false;
  const recaudado = count * PRICE;
  const recaudadoPago = students.filter((s) => s.paid).length * PRICE;
  const cuposLibres = MAX_CUPOS - count;

  return (
    <div style={{ padding: '1rem 0', maxWidth: 560, margin: '0 auto', fontFamily: "'Albert Sans', sans-serif" }}>
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 16,
          marginBottom: '1.25rem',
          background: 'linear-gradient(135deg, #FBEAF0 0%, #FAECE7 100%)',
          borderRadius: 16,
          padding: '1rem 1.5rem',
        }}
      >
        <PoleIllustration />
        <div>
          <h2 style={{ margin: '0 0 4px', fontSize: 22, fontWeight: 500, color: '#4B1528' }}>
            Pole en español
          </h2>
          <p style={{ margin: '0 0 2px', fontSize: 15, fontWeight: 500, color: '#72243E' }}>
            4 clases en agosto
          </p>
          <p style={{ margin: 0, fontSize: 13, color: '#993556' }}>
            {PRICE} kr el mes completo · cupos limitados a {MAX_CUPOS} personas
          </p>
        </div>
      </div>

      <div
        style={{
          background: '#FFFBFC',
          border: '0.5px solid #F0DCE3',
          borderRadius: 12,
          padding: '1rem 1.25rem',
          marginBottom: '1.25rem',
          fontSize: 14,
          color: '#5C2A3C',
          lineHeight: 1.55,
        }}
      >
        <p style={{ margin: '0 0 8px' }}>
          Vamos a aprender giros, inversiones, agarres, trucos y combos, en grupo chico (máximo {MAX_CUPOS} personas) y en español, con atención personalizada en cada clase. Vas a ver cómo tu cuerpo se vuelve más fuerte, flexible y seguro de sí mismo, mientras entrenás algo que te divierte de principio a fin.
        </p>
        <p style={{ margin: 0 }}>
          <strong>Fechas del mes:</strong> Lunes 3, 17, 24 y 31 de agosto (18:30 hs).
        </p>
      </div>

      {/* Calendario de Julio */}
      <div
        style={{
          background: '#FFFBFC',
          border: '0.5px solid #F0DCE3',
          borderRadius: 12,
          padding: '1rem 1.25rem',
          marginBottom: '1.25rem',
        }}
      >
        <p style={{ margin: '0 0 12px', fontSize: 13, fontWeight: 600, color: '#72243E', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
          Agosto 2026
        </p>
        {(() => {
          const classDays = new Set([3, 17, 24, 31]);
          const dayNames = ['Lu', 'Ma', 'Mi', 'Ju', 'Vi', 'Sa', 'Do'];
          // Agosto 2026: el día 1 cae en sábado (índice 5 en semana Lu-Do)
          const startOffset = 5;
          const totalDays = 31;
          const cells = [];

          // Encabezados
          const headers = dayNames.map((d) => (
            <div
              key={d}
              style={{
                textAlign: 'center',
                fontSize: 11,
                fontWeight: 600,
                color: '#C49DAA',
                padding: '4px 0',
              }}
            >
              {d}
            </div>
          ));

          // Celdas vacías iniciales
          for (let i = 0; i < startOffset; i++) {
            cells.push(<div key={`empty-${i}`} />);
          }

          // Días del mes
          for (let day = 1; day <= totalDays; day++) {
            const isClass = classDays.has(day);
            cells.push(
              <div
                key={day}
                style={{
                  textAlign: 'center',
                  padding: '5px 2px',
                  borderRadius: 8,
                  background: isClass ? '#D4537E' : 'transparent',
                  color: isClass ? '#fff' : '#5C2A3C',
                  fontWeight: isClass ? 700 : 400,
                  fontSize: 13,
                }}
                title={isClass ? `Lunes ${day} — 18:30 hs` : ''}
              >
                {day}
                {isClass && (
                  <div style={{ fontSize: 7, color: '#FFD6E7', lineHeight: 1, marginTop: 1 }}>18:30</div>
                )}
              </div>
            );
          }

          return (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '2px' }}>
              {headers}
              {cells}
            </div>
          );
        })()}
      </div>

      {/* Lista de alumnas — solo visible para la instructora */}
      {adminMode && (
        <div
          style={{
            background: '#FBEAF0',
            borderRadius: 14,
            border: '0.5px solid #F0C8D6',
            overflow: 'hidden',
            marginBottom: '1.25rem',
          }}
        >
          <div style={{ padding: 14, borderBottom: '0.5px solid #F0C8D6' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
              <span style={{ fontWeight: 500, fontSize: 16, color: '#4B1528' }}>Alumnas inscriptas</span>
              <span style={{ fontSize: 13, fontWeight: 500, color: full ? '#993556' : '#72243E' }}>
                {count}/{MAX_CUPOS} {full ? '· lleno' : `· ${cuposLibres} libres`}
              </span>
            </div>
            <div style={{ height: 7, background: '#F4D6E2', borderRadius: 4, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${pct}%`, background: full ? '#D4537E' : '#D85A30', transition: 'width 0.2s ease' }} />
            </div>
          </div>
          <div style={{ background: '#FFFBFC' }}>
            {students.length === 0 ? (
              <p style={{ padding: '1.5rem 1rem', textAlign: 'center', color: '#A87C8C', fontSize: 13, margin: 0 }}>
                Sin reservas todavía.
              </p>
            ) : (
              students.map((s) => (
                <div key={s.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 14px', borderBottom: '0.5px solid #F0DCE3', fontSize: 14 }}>
                  <span style={{ color: '#4B1528' }}>{s.name}</span>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexShrink: 0 }}>
                    <span style={{ fontSize: 11, padding: '3px 9px', borderRadius: 6, border: '0.5px solid #D9B8C4', background: s.paid ? '#E0F0E5' : '#FBEAF0', color: s.paid ? '#1D6B3E' : '#993556' }}>
                      {s.paid ? 'Pago' : 'Pendiente'}
                    </span>
                    <button onClick={() => togglePaid(s.id)} style={{ fontSize: 11, padding: '3px 9px', height: 'auto', borderRadius: 6, border: '0.5px solid #D9B8C4', background: '#fff', color: '#72243E', cursor: 'pointer' }}>
                      cambiar
                    </button>
                    <button onClick={() => removeStudent(s.id)} aria-label="Eliminar" style={{ fontSize: 11, padding: '3px 7px', height: 'auto', borderRadius: 6, border: '0.5px solid #D9B8C4', background: '#fff', color: '#993556', cursor: 'pointer' }}>
                      ✕
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {step === 'form' && (
        <div
          style={{
            background: 'linear-gradient(135deg, #D4537E 0%, #B03060 100%)',
            borderRadius: 16,
            padding: '1.5rem',
            marginBottom: '1.25rem',
            boxShadow: '0 4px 16px rgba(212, 83, 126, 0.3)',
          }}
        >
          <p style={{ margin: '0 0 4px', fontSize: 18, fontWeight: 700, color: '#fff', letterSpacing: '-0.01em' }}>
            ¿Te anotás?
          </p>
          <p style={{ margin: '0 0 16px', fontSize: 13, color: 'rgba(255,255,255,0.8)' }}>
            {full ? 'No quedan lugares disponibles para este mes.' : 'Reservá tu lugar para agosto.'}
          </p>
          <label
            htmlFor="student-name-input"
            style={{ display: 'block', fontSize: 13, fontWeight: 500, color: 'rgba(255,255,255,0.9)', marginBottom: 8 }}
          >
            Escribí tu nombre completo
          </label>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            <input
              id="student-name-input"
              type="text"
              placeholder="Ej: María Pérez"
              value={name}
              onChange={(e) => setName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
              disabled={full}
              style={{
                flex: 1,
                minWidth: 180,
                fontSize: 15,
                padding: '11px 14px',
                borderRadius: 10,
                border: 'none',
                background: '#fff',
                color: '#4B1528',
                outline: 'none',
                boxShadow: '0 2px 8px rgba(0,0,0,0.12)',
              }}
            />
            <button
              onClick={handleAdd}
              disabled={full}
              style={{
                flex: '0 0 auto',
                background: full ? 'rgba(255,255,255,0.3)' : '#fff',
                color: full ? 'rgba(255,255,255,0.6)' : '#D4537E',
                border: 'none',
                borderRadius: 10,
                padding: '0 20px',
                fontWeight: 700,
                fontSize: 15,
                cursor: full ? 'not-allowed' : 'pointer',
                boxShadow: full ? 'none' : '0 2px 8px rgba(0,0,0,0.12)',
              }}
            >
              {full ? 'Sin cupos' : 'Reservar →'}
            </button>
          </div>
          {error && (
            <p style={{ color: 'rgba(255,255,255,0.9)', fontSize: 13, margin: '10px 0 0', background: 'rgba(0,0,0,0.15)', borderRadius: 8, padding: '8px 12px' }}>{error}</p>
          )}
        </div>
      )}

      {step === 'payment' && (
        <div
          style={{
            background: '#FBEAF0',
            border: '0.5px solid #F0C8D6',
            borderRadius: 14,
            padding: '1.25rem',
            marginBottom: '1rem',
          }}
        >
          <p style={{ margin: '0 0 4px', fontSize: 15, fontWeight: 500, color: '#4B1528' }}>
            ¡Tu lugar está reservado! 🎉
          </p>
          <p style={{ margin: '0 0 14px', fontSize: 13, color: '#993556' }}>
            Para confirmarlo, pagá {PRICE} kr por el mes completo (4 clases) y avisá que ya pagaste.
          </p>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            <div
              style={{
                background: '#FFFBFC',
                border: '0.5px solid #F0DCE3',
                borderRadius: 10,
                padding: '0.75rem 1rem',
              }}
            >
              <p style={{ margin: '0 0 2px', fontSize: 12, color: '#A87C8C' }}>MobilePay</p>
              <p style={{ margin: 0, fontSize: 16, fontWeight: 500, color: '#4B1528' }}>
                {MOBILEPAY_NUMBER}
              </p>
            </div>
            <div
              style={{
                background: '#FFFBFC',
                border: '0.5px solid #F0DCE3',
                borderRadius: 10,
                padding: '0.75rem 1rem',
              }}
            >
              <p style={{ margin: '0 0 2px', fontSize: 12, color: '#A87C8C' }}>Revolut</p>
              <a
                href={REVOLUT_LINK}
                target="_blank"
                rel="noopener noreferrer"
                style={{ fontSize: 16, fontWeight: 500, color: '#D4537E', textDecoration: 'none' }}
              >
                {REVOLUT_HANDLE}
              </a>
            </div>
          </div>

          <p style={{ margin: '14px 0 0', fontSize: 12, color: '#A87C8C' }}>
            Importante: poné tu nombre en el concepto del pago para que la profe pueda identificarlo.
          </p>

          <button
            onClick={confirmPaid}
            style={{
              marginTop: 14,
              width: '100%',
              background: '#D4537E',
              color: '#fff',
              border: 'none',
              borderRadius: 8,
              padding: '10px 0',
              fontWeight: 500,
              cursor: 'pointer',
            }}
          >
            Ya pagué
          </button>
        </div>
      )}

      {step === 'done' && (
        <div
          style={{
            background: '#E0F0E5',
            border: '0.5px solid #BFE0CB',
            borderRadius: 14,
            padding: '1.25rem',
            marginBottom: '1rem',
            textAlign: 'center',
          }}
        >
          <p style={{ margin: '0 0 4px', fontSize: 15, fontWeight: 500, color: '#1D6B3E' }}>
            ¡Listo! Reserva confirmada 💚
          </p>
          <p style={{ margin: '0 0 14px', fontSize: 13, color: '#1D6B3E' }}>
            Nos vemos el lunes 18:30 hs. La profe va a verificar tu pago antes de la primera clase.
          </p>
          <button
            onClick={resetForm}
            style={{
              background: '#fff',
              border: '0.5px solid #BFE0CB',
              borderRadius: 8,
              padding: '6px 16px',
              fontSize: 13,
              color: '#1D6B3E',
              cursor: 'pointer',
            }}
          >
            Anotar a otra persona
          </button>
        </div>
      )}

      {saving && (
        <p style={{ color: '#A87C8C', fontSize: 12, margin: '0 0 1rem' }}>Guardando...</p>
      )}

      <div
        style={{
          marginTop: '1.5rem',
          paddingTop: '1rem',
          borderTop: '0.5px solid #F0DCE3',
        }}
      >
        <button
          onClick={handleAdminClick}
          style={{
            fontSize: 13,
            background: '#fff',
            border: '0.5px solid #D9B8C4',
            borderRadius: 8,
            padding: '6px 14px',
            color: '#72243E',
            cursor: 'pointer',
          }}
        >
          {adminMode ? 'Ocultar panel de instructora' : 'Soy la instructora'}
        </button>

        {showPasswordPrompt && !adminMode && (
          <div
            style={{
              marginTop: '0.75rem',
              display: 'flex',
              gap: 8,
              alignItems: 'center',
              flexWrap: 'wrap',
            }}
          >
            <input
              type="password"
              value={passwordInput}
              onChange={(e) => {
                setPasswordInput(e.target.value);
                setPasswordError('');
              }}
              onKeyDown={(e) => {
                if (e.key === 'Enter') checkPassword();
              }}
              placeholder="Contraseña"
              style={{
                fontSize: 14,
                padding: '6px 10px',
                borderRadius: 8,
                border: '0.5px solid #D9B8C4',
                outline: 'none',
              }}
            />
            <button
              onClick={checkPassword}
              style={{
                fontSize: 13,
                background: '#72243E',
                color: '#fff',
                border: 'none',
                borderRadius: 8,
                padding: '6px 14px',
                cursor: 'pointer',
              }}
            >
              Entrar
            </button>
            {passwordError && (
              <span style={{ fontSize: 12, color: '#B3261E' }}>{passwordError}</span>
            )}
          </div>
        )}

        {adminMode && (
          <div
            style={{
              marginTop: '1rem',
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
              gap: 12,
            }}
          >
            <div style={{ background: '#FAECE7', borderRadius: 10, padding: '1rem' }}>
              <p style={{ fontSize: 13, color: '#993556', margin: '0 0 4px' }}>Alumnas</p>
              <p style={{ fontSize: 22, fontWeight: 500, margin: 0, color: '#4B1528' }}>
                {count}
              </p>
            </div>
            <div style={{ background: '#FAECE7', borderRadius: 10, padding: '1rem' }}>
              <p style={{ fontSize: 13, color: '#993556', margin: '0 0 4px' }}>
                Recaudado / pagado
              </p>
              <p style={{ fontSize: 22, fontWeight: 500, margin: 0, color: '#4B1528' }}>
                {recaudadoPago.toLocaleString('da-DK')}{' '}
                <span style={{ fontSize: 13, color: '#A87C8C' }}>
                  / {recaudado.toLocaleString('da-DK')} kr
                </span>
              </p>
            </div>
            <div style={{ background: '#FAECE7', borderRadius: 10, padding: '1rem' }}>
              <p style={{ fontSize: 13, color: '#993556', margin: '0 0 4px' }}>
                Costo estudio
              </p>
              <p style={{ fontSize: 22, fontWeight: 500, margin: 0, color: '#4B1528' }}>
                1.800 kr
              </p>
            </div>
            <div style={{ background: '#E0F0E5', borderRadius: 10, padding: '1rem' }}>
              <p style={{ fontSize: 13, color: '#1D6B3E', margin: '0 0 4px' }}>
                Tu ganancia
              </p>
              <p style={{ fontSize: 22, fontWeight: 500, margin: 0, color: '#1D6B3E' }}>
                {(recaudado - 1800).toLocaleString('da-DK')} kr
              </p>
            </div>
          </div>
        )}
      </div>

      <p style={{ marginTop: '1.5rem', fontSize: 12, color: '#C49DAA' }}>
        Nota: este link es compartido — cualquiera con el link puede ver y anotarse. El pago se confirma manualmente, no es automático.
      </p>
    </div>
  );
}
